import chromadb
from langchain import PromptTemplate, LLMChain, VectorDBRetriever
from langchain.chat_models import ChatOpenAI
from langchain.embeddings import OpenAIEmbeddings

# Load company documents into vector database
embeddings = OpenAIEmbeddings()
client = chromadb.Client()
collection = client.create_collection(name="company_documents")
collection.add(embeddings.embed_documents(documents), metadatas=documents)

# Create retriever object
retriever = VectorDBRetriever(
    collection=collection,
    embedding=embeddings,
)

# Create LLM prompt template
prompt = PromptTemplate(
    input_variables=["query", "context"],
    template="Answer the user query based on the provided context:\n\nQuery: {query}\n\nContext: {context}",
)

# Create LLM chain
llm = ChatOpenAI(temperature=0)
chain = LLMChain(prompt=prompt, llm=llm, retriever=retriever)

# Accept user query and retrieve relevant context
query = input("Enter your query: ")
result = chain({"query": query})

# Print the retrieved context and LLM response
print("Retrieved Context:", result["context"])
print("LLM Response:", result["text"])